mapper.select:
SELECT TBL_INV_PRODUCT_ID as tblInvProductId, CMPY_CD as cmpyCd, AGNT_CD as agntCd, AGNT_NM as agntNm, TBL_MTRL_M_ID as tblProductMId, MTRL_CD as productCd, MTRL_NM as productNm, CURRENT_QTY as currentQty, SAVE_TIME as saveTime, SAVE_USER as saveUser, UPDT_TIME as updtTime, UPDT_USER as updtUser FROM TBL_INV_PRODUCT WHERE 1=1
AND CMPY_CD = #{cmpyCd}
AND AGNT_CD = #{agntCd}
AND MTRL_CD LIKE '%' + #{productCd} + '%'
AND MTRL_NM LIKE '%' + #{productNm} + '%'
ORDER BY MTRL_CD

mapper.update:
UPDATE TBL_INV_PRODUCT 
SET CURRENT_QTY = #{afterQty},
    UPDT_TIME = GETDATE(),
    UPDT_USER = ISNULL(#{saveUser}, 'SYSTEM')
WHERE CMPY_CD = #{cmpyCd}
  AND AGNT_CD = #{agntCd}
  AND MTRL_CD = #{productCd}
